                // Try to reconnect using the same handle
                if (conn->reconnect()) {
                    conn->set_state(ConnectionState::IN_USE);
                    in_use_.insert(h);
                    total_acquired_++;
                    return conn;
                }

                // Connection is dead, remove it
                remove_connection_internal(h);
