int main() {
    std::cout << "=== Network Client Connection Pool Demo ===" << std::endl;

    NetworkClient client("127.0.0.1", 8080, 3, 10);

    std::cout << "\n--- Initial State ---" << std::endl;
    client.print_stats();

    // Single-threaded test
    std::cout << "\n--- Single-threaded requests ---" << std::endl;
    for (int i = 0; i < 10; ++i) {
        std::string response;
        std::string request = "Request-" + std::to_string(i);
        bool ok = client.send_request(request, response);
        std::cout << "  [" << i << "] " << request << " -> "
                  << (ok ? "OK: " + response : "FAILED") << std::endl;
    }

    client.print_stats();

    // Multi-threaded test
    std::cout << "\n--- Multi-threaded requests (8 threads, 20 requests each) ---" << std::endl;
    std::vector<std::thread> threads;
    std::atomic<int> success_count{0};
    std::atomic<int> failure_count{0};

    for (int t = 0; t < 8; ++t) {
        threads.emplace_back([&client, t, &success_count, &failure_count]() {
            for (int i = 0; i < 20; ++i) {
                std::string response;
                std::string request = "T" + std::to_string(t) + "-R" + std::to_string(i);
                
                bool ok = client.send_request_reliable(request, response);
                if (ok) {
                    success_count++;
                } else {
                    failure_count++;
                }
            }
        });
    }

    for (auto& t : threads) {
        t.join();
    }

    std::cout << "\n--- Final Results ---" << std::endl;
    std::cout << "  Successes: " << success_count << std::endl;
    std::cout << "  Failures: " << failure_count << std::endl;
    client.print_stats();

    // Test handle reuse with manual connection management
    std::cout << "\n--- Handle reuse test ---" << std::endl;
    {
        ConnectionConfig config;
        config.host = "127.0.0.1";
        config.port = 9090;
        config.max_retries = 5;
        config.retry_delay_ms = 50;

        ConnectionPool::PoolConfig pool_config;
        pool_config.min_connections = 1;
        pool_config.max_connections = 2;

        ConnectionPool pool(config, pool_config);

        auto conn = pool.acquire();
        if (conn) {
            auto handle = conn->get_handle();
            std::cout << "  Got connection handle: " << handle << std::endl;
            std::cout << "  " << conn->stats() << std::endl;

            // Simulate usage
            const char* msg = "hello";
            int result = conn->send_with_retry(msg, strlen(msg));
            std::cout << "  Send result: " << result << std::endl;

            if (result < 0) {
                // Connection errored, but handle stays valid for retry
                std::cout << "  Attempting reconnect on same handle..." << std::endl;
                if (conn->reconnect()) {
                    result = conn->send(msg, strlen(msg));
                    std::cout << "  Retry send result: " << result << std::endl;
                }
            }

            std::cout << "  " << conn->stats() << std::endl;
            pool.release(conn);
        }

        pool.print_stats();
        pool.shutdown();
    }

    std::cout << "\n=== Demo Complete ===" << std::endl;
    return 0;
}